package workflow

import (
	"fmt"
	"os"
	"path/filepath"
	"strconv"
	"strings"

	"github.com/github/gh-aw/pkg/logger"
)

var maintenanceLog = logger.New("workflow:maintenance_workflow")

// generateInstallCLISteps generates YAML steps to install or build the gh-aw CLI.
// In dev mode: builds from source using Setup Go + Build gh-aw (./gh-aw binary available)
// In release mode: installs the released CLI via the setup-cli action (gh aw available)
// In action mode: installs the released CLI via the gh-aw-actions/setup-cli action (gh aw available)
func generateInstallCLISteps(actionMode ActionMode, version string, actionTag string) string {
	if actionMode == ActionModeDev {
		return `      - name: Setup Go
        uses: ` + GetActionPin("actions/setup-go") + `
        with:
          go-version-file: go.mod
          cache: true

      - name: Build gh-aw
        run: make build

`
	}

	cliTag := actionTag
	if cliTag == "" {
		cliTag = version
	}

	// Action mode: use setup-cli action from external gh-aw-actions repository
	if actionMode == ActionModeAction {
		return `      - name: Install gh-aw
        uses: github/gh-aw-actions/setup-cli@` + cliTag + `
        with:
          version: ` + cliTag + `

`
	}

	// Release mode: use setup-cli action (consistent with copilot-setup-steps.yml)
	return `      - name: Install gh-aw
        uses: github/gh-aw/actions/setup-cli@` + cliTag + `
        with:
          version: ` + cliTag + `

`
}

// getCLICmdPrefix returns the CLI command prefix based on action mode.
// In dev mode: "./gh-aw" (local binary built from source)
// In release mode: "gh aw" (installed via gh extension)
func getCLICmdPrefix(actionMode ActionMode) string {
	if actionMode == ActionModeDev {
		return "./gh-aw"
	}
	return "gh aw"
}

// generateMaintenanceCron generates a cron schedule based on the minimum expires value in days
// Schedule runs at minimum required frequency to check expirations at appropriate intervals
// Returns cron expression and description.
func generateMaintenanceCron(minExpiresDays int) (string, string) {
	// Use a pseudo-random but deterministic minute (37) to avoid load spikes at :00
	minute := 37

	// Determine frequency based on minimum expires value (in days)
	// Run at least as often as the shortest expiration would need
	if minExpiresDays <= 1 {
		// For 1 day or less, run every 2 hours
		return fmt.Sprintf("%d */2 * * *", minute), "Every 2 hours"
	} else if minExpiresDays == 2 {
		// For 2 days, run every 6 hours
		return fmt.Sprintf("%d */6 * * *", minute), "Every 6 hours"
	} else if minExpiresDays <= 4 {
		// For 3-4 days, run every 12 hours
		return fmt.Sprintf("%d */12 * * *", minute), "Every 12 hours"
	}

	// For more than 4 days, run daily
	return fmt.Sprintf("%d %d * * *", minute, 0), "Daily"
}

// GenerateMaintenanceWorkflow generates the agentics-maintenance.yml workflow
// if any workflows use the expires field for discussions or issues
func GenerateMaintenanceWorkflow(workflowDataList []*WorkflowData, workflowDir string, version string, actionMode ActionMode, actionTag string, verbose bool) error {
	maintenanceLog.Print("Checking if maintenance workflow is needed")

	// Check if any workflow uses expires field for discussions, issues, or pull requests
	// and track the minimum expires value to determine schedule frequency
	hasExpires := false
	minExpires := 0 // Track minimum expires value in hours

	for _, workflowData := range workflowDataList {
		if workflowData.SafeOutputs != nil {
			// Check for expired discussions
			if workflowData.SafeOutputs.CreateDiscussions != nil {
				if workflowData.SafeOutputs.CreateDiscussions.Expires > 0 {
					hasExpires = true
					expires := workflowData.SafeOutputs.CreateDiscussions.Expires
					maintenanceLog.Printf("Workflow %s has expires field set to %d hours for discussions", workflowData.Name, expires)
					if minExpires == 0 || expires < minExpires {
						minExpires = expires
					}
				}
			}
			// Check for expired issues
			if workflowData.SafeOutputs.CreateIssues != nil {
				if workflowData.SafeOutputs.CreateIssues.Expires > 0 {
					hasExpires = true
					expires := workflowData.SafeOutputs.CreateIssues.Expires
					maintenanceLog.Printf("Workflow %s has expires field set to %d hours for issues", workflowData.Name, expires)
					if minExpires == 0 || expires < minExpires {
						minExpires = expires
					}
				}
			}
			// Check for expired pull requests
			if workflowData.SafeOutputs.CreatePullRequests != nil {
				if workflowData.SafeOutputs.CreatePullRequests.Expires > 0 {
					hasExpires = true
					expires := workflowData.SafeOutputs.CreatePullRequests.Expires
					maintenanceLog.Printf("Workflow %s has expires field set to %d hours for pull requests", workflowData.Name, expires)
					if minExpires == 0 || expires < minExpires {
						minExpires = expires
					}
				}
			}
		}
	}

	if !hasExpires {
		maintenanceLog.Print("No workflows use expires field, skipping maintenance workflow generation")

		// Delete existing maintenance workflow file if it exists (no expires means no need for maintenance)
		maintenanceFile := filepath.Join(workflowDir, "agentics-maintenance.yml")
		if _, err := os.Stat(maintenanceFile); err == nil {
			maintenanceLog.Printf("Deleting existing maintenance workflow: %s", maintenanceFile)
			if err := os.Remove(maintenanceFile); err != nil {
				return fmt.Errorf("failed to delete maintenance workflow: %w", err)
			}
			maintenanceLog.Print("Maintenance workflow deleted successfully")
		}

		return nil
	}

	maintenanceLog.Printf("Generating maintenance workflow for expired discussions, issues, and pull requests (minimum expires: %d hours)", minExpires)

	// Convert hours to days for cron schedule generation
	minExpiresDays := minExpires / 24
	if minExpires%24 > 0 {
		minExpiresDays++ // Round up partial days
	}

	// Generate cron schedule based on minimum expires value
	cronSchedule, scheduleDesc := generateMaintenanceCron(minExpiresDays)
	maintenanceLog.Printf("Maintenance schedule: %s (%s)", cronSchedule, scheduleDesc)

	// Create the maintenance workflow content using strings.Builder
	var yaml strings.Builder

	// Add workflow header with logo and instructions
	customInstructions := `Alternative regeneration methods:
  make recompile

Or use the gh-aw CLI directly:
  ./gh-aw compile --validate --verbose

The workflow is generated when any workflow uses the 'expires' field
in create-discussions, create-issues, or create-pull-request safe-outputs configuration.
Schedule frequency is automatically determined by the shortest expiration time.`

	header := GenerateWorkflowHeader("", "pkg/workflow/maintenance_workflow.go", customInstructions)
	yaml.WriteString(header)

	yaml.WriteString(`name: Agentic Maintenance

on:
  schedule:
    - cron: "` + cronSchedule + `"  # ` + scheduleDesc + ` (based on minimum expires: ` + strconv.Itoa(minExpiresDays) + ` days)
  workflow_dispatch:
    inputs:
      operation:
        description: 'Optional maintenance operation to run'
        required: false
        type: choice
        default: ''
        options:
          - ''
          - 'disable'
          - 'enable'
          - 'update'
          - 'upgrade'
          - 'safe_outputs'
      run_url:
        description: 'Run URL or run ID to replay safe outputs from (e.g. https://github.com/owner/repo/actions/runs/12345 or 12345). Required when operation is safe_outputs.'
        required: false
        type: string
        default: ''

permissions: {}

jobs:
  close-expired-entities:
    if: ${{ !github.event.repository.fork && (github.event_name != 'workflow_dispatch' || github.event.inputs.operation == '') }}
    runs-on: ubuntu-slim
    permissions:
      discussions: write
      issues: write
      pull-requests: write
    steps:
`)

	// Get the setup action reference (local or remote based on mode)
	// Use the first available WorkflowData's ActionResolver to enable SHA pinning
	var resolver ActionSHAResolver
	if len(workflowDataList) > 0 && workflowDataList[0].ActionResolver != nil {
		resolver = workflowDataList[0].ActionResolver
	}
	setupActionRef := ResolveSetupActionReference(actionMode, version, actionTag, resolver)

	// Add checkout step only in dev/script mode (for local action paths)
	if actionMode == ActionModeDev || actionMode == ActionModeScript {
		yaml.WriteString("      - name: Checkout actions folder\n")
		yaml.WriteString("        uses: " + GetActionPin("actions/checkout") + "\n")
		yaml.WriteString("        with:\n")
		yaml.WriteString("          sparse-checkout: |\n")
		yaml.WriteString("            actions\n")
		yaml.WriteString("          persist-credentials: false\n\n")
	}

	// Add setup step with the resolved action reference
	yaml.WriteString(`      - name: Setup Scripts
        uses: ` + setupActionRef + `
        with:
          destination: ${{ runner.temp }}/gh-aw/actions

      - name: Close expired discussions
        uses: ` + GetActionPin("actions/github-script") + `
        with:
          script: |
`)

	// Add the close expired discussions script using require()
	yaml.WriteString(`            const { setupGlobals } = require('${{ runner.temp }}/gh-aw/actions/setup_globals.cjs');
            setupGlobals(core, github, context, exec, io);
            const { main } = require('${{ runner.temp }}/gh-aw/actions/close_expired_discussions.cjs');
            await main();

      - name: Close expired issues
        uses: ` + GetActionPin("actions/github-script") + `
        with:
          script: |
`)

	// Add the close expired issues script using require()
	yaml.WriteString(`            const { setupGlobals } = require('${{ runner.temp }}/gh-aw/actions/setup_globals.cjs');
            setupGlobals(core, github, context, exec, io);
            const { main } = require('${{ runner.temp }}/gh-aw/actions/close_expired_issues.cjs');
            await main();

      - name: Close expired pull requests
        uses: ` + GetActionPin("actions/github-script") + `
        with:
          script: |
`)

	// Add the close expired pull requests script using require()
	yaml.WriteString(`            const { setupGlobals } = require('${{ runner.temp }}/gh-aw/actions/setup_globals.cjs');
            setupGlobals(core, github, context, exec, io);
            const { main } = require('${{ runner.temp }}/gh-aw/actions/close_expired_pull_requests.cjs');
            await main();
`)

	// Add unified run_operation job for all dispatch operations except safe_outputs
	yaml.WriteString(`
  run_operation:
    if: ${{ github.event_name == 'workflow_dispatch' && github.event.inputs.operation != '' && github.event.inputs.operation != 'safe_outputs' && !github.event.repository.fork }}
    runs-on: ubuntu-slim
    permissions:
      actions: write
      contents: write
      pull-requests: write
    steps:
      - name: Checkout repository
        uses: ` + GetActionPin("actions/checkout") + `
        with:
          persist-credentials: false

      - name: Setup Scripts
        uses: ` + setupActionRef + `
        with:
          destination: ${{ runner.temp }}/gh-aw/actions

      - name: Check admin/maintainer permissions
        uses: ` + GetActionPin("actions/github-script") + `
        with:
          github-token: ${{ secrets.GITHUB_TOKEN }}
          script: |
            const { setupGlobals } = require('${{ runner.temp }}/gh-aw/actions/setup_globals.cjs');
            setupGlobals(core, github, context, exec, io);
            const { main } = require('${{ runner.temp }}/gh-aw/actions/check_team_member.cjs');
            await main();

`)

	yaml.WriteString(generateInstallCLISteps(actionMode, version, actionTag))
	yaml.WriteString(`      - name: Run operation
        uses: ` + GetActionPin("actions/github-script") + `
        env:
          GH_TOKEN: ${{ secrets.GITHUB_TOKEN }}
          GH_AW_OPERATION: ${{ github.event.inputs.operation }}
          GH_AW_CMD_PREFIX: ` + getCLICmdPrefix(actionMode) + `
        with:
          github-token: ${{ secrets.GITHUB_TOKEN }}
          script: |
            const { setupGlobals } = require('${{ runner.temp }}/gh-aw/actions/setup_globals.cjs');
            setupGlobals(core, github, context, exec, io);
            const { main } = require('${{ runner.temp }}/gh-aw/actions/run_operation_update_upgrade.cjs');
            await main();
`)

	// Add apply_safe_outputs job for workflow_dispatch with operation == 'safe_outputs'
	yaml.WriteString(`
  apply_safe_outputs:
    if: ${{ github.event_name == 'workflow_dispatch' && github.event.inputs.operation == 'safe_outputs' && !github.event.repository.fork }}
    runs-on: ubuntu-slim
    permissions:
      actions: read
      contents: write
      discussions: write
      issues: write
      pull-requests: write
    steps:
      - name: Checkout actions folder
        uses: ` + GetActionPin("actions/checkout") + `
        with:
          sparse-checkout: |
            actions
          persist-credentials: false

      - name: Setup Scripts
        uses: ` + setupActionRef + `
        with:
          destination: ${{ runner.temp }}/gh-aw/actions

      - name: Check admin/maintainer permissions
        uses: ` + GetActionPin("actions/github-script") + `
        with:
          github-token: ${{ secrets.GITHUB_TOKEN }}
          script: |
            const { setupGlobals } = require('${{ runner.temp }}/gh-aw/actions/setup_globals.cjs');
            setupGlobals(core, github, context, exec, io);
            const { main } = require('${{ runner.temp }}/gh-aw/actions/check_team_member.cjs');
            await main();

      - name: Apply Safe Outputs
        uses: ` + GetActionPin("actions/github-script") + `
        env:
          GH_TOKEN: ${{ secrets.GITHUB_TOKEN }}
          GH_AW_RUN_URL: ${{ github.event.inputs.run_url }}
        with:
          github-token: ${{ secrets.GITHUB_TOKEN }}
          script: |
            const { setupGlobals } = require('${{ runner.temp }}/gh-aw/actions/setup_globals.cjs');
            setupGlobals(core, github, context, exec, io);
            const { main } = require('${{ runner.temp }}/gh-aw/actions/apply_safe_outputs_replay.cjs');
            await main();
`)

	// Add compile-workflows and zizmor-scan jobs only in dev mode
	// These jobs are specific to the gh-aw repository and require go.mod, make build, etc.
	// User repositories won't have these dependencies, so we skip them in release mode
	if actionMode == ActionModeDev {
		// Add compile-workflows job
		yaml.WriteString(`
  compile-workflows:
    if: ${{ !github.event.repository.fork && (github.event_name != 'workflow_dispatch' || github.event.inputs.operation == '') }}
    runs-on: ubuntu-slim
    permissions:
      contents: read
      issues: write
    steps:
`)

		// Dev mode: checkout entire repository (no sparse checkout, but no credentials)
		yaml.WriteString(`      - name: Checkout repository
        uses: actions/checkout@11bd71901bbe5b1630ceea73d27597364c9af683 # v4.2.2
        with:
          persist-credentials: false

`)

		yaml.WriteString(generateInstallCLISteps(actionMode, version, actionTag))
		yaml.WriteString(`      - name: Compile workflows
        run: |
          ` + getCLICmdPrefix(actionMode) + ` compile --validate --verbose
          echo "✓ All workflows compiled successfully"

      - name: Setup Scripts
        uses: ` + setupActionRef + `
        with:
          destination: ${{ runner.temp }}/gh-aw/actions

      - name: Check for out-of-sync workflows and create issue if needed
        uses: ` + GetActionPin("actions/github-script") + `
        with:
          script: |
            const { setupGlobals } = require('${{ runner.temp }}/gh-aw/actions/setup_globals.cjs');
            setupGlobals(core, github, context, exec, io);
            const { main } = require('${{ runner.temp }}/gh-aw/actions/check_workflow_recompile_needed.cjs');
            await main();

  zizmor-scan:
    if: ${{ !github.event.repository.fork && (github.event_name != 'workflow_dispatch' || github.event.inputs.operation == '') }}
    runs-on: ubuntu-slim
    needs: compile-workflows
    permissions:
      contents: read
    steps:
      - name: Checkout repository
        uses: actions/checkout@11bd71901bbe5b1630ceea73d27597364c9af683 # v4.2.2

      - name: Setup Go
        uses: actions/setup-go@41dfa10bad2bb2ae585af6ee5bb4d7d973ad74ed # v5.1.0
        with:
          go-version-file: go.mod
          cache: true

      - name: Build gh-aw
        run: make build

      - name: Run zizmor security scanner
        run: |
          ./gh-aw compile --zizmor --verbose
          echo "✓ Zizmor security scan completed"

  secret-validation:
    if: ${{ !github.event.repository.fork && (github.event_name != 'workflow_dispatch' || github.event.inputs.operation == '') }}
    runs-on: ubuntu-slim
    permissions:
      contents: read
    steps:
`)

		// Add checkout step only in dev mode (for local action paths)
		if actionMode == ActionModeDev {
			yaml.WriteString(`      - name: Checkout actions folder
        uses: ` + GetActionPin("actions/checkout") + `
        with:
          sparse-checkout: |
            actions
          persist-credentials: false

`)
		}

		yaml.WriteString(`      - name: Setup Node.js
        uses: actions/setup-node@39370e3970a6d050c480ffad4ff0ed4d3fdee5af # v4.1.0
        with:
          node-version: '22'

      - name: Setup Scripts
        uses: ` + setupActionRef + `
        with:
          destination: ${{ runner.temp }}/gh-aw/actions

      - name: Validate Secrets
        uses: ` + GetActionPin("actions/github-script") + `
        env:
          # GitHub tokens
          GH_AW_GITHUB_TOKEN: ${{ secrets.GH_AW_GITHUB_TOKEN }}
          GH_AW_GITHUB_MCP_SERVER_TOKEN: ${{ secrets.GH_AW_GITHUB_MCP_SERVER_TOKEN }}
          GH_AW_PROJECT_GITHUB_TOKEN: ${{ secrets.GH_AW_PROJECT_GITHUB_TOKEN }}
          GH_AW_COPILOT_TOKEN: ${{ secrets.GH_AW_COPILOT_TOKEN }}
          # AI Engine API keys
          ANTHROPIC_API_KEY: ${{ secrets.ANTHROPIC_API_KEY }}
          OPENAI_API_KEY: ${{ secrets.OPENAI_API_KEY }}
          BRAVE_API_KEY: ${{ secrets.BRAVE_API_KEY }}
          # Integration tokens
          NOTION_API_TOKEN: ${{ secrets.NOTION_API_TOKEN }}
        with:
          script: |
            const { setupGlobals } = require('${{ runner.temp }}/gh-aw/actions/setup_globals.cjs');
            setupGlobals(core, github, context, exec, io);
            const { main } = require('${{ runner.temp }}/gh-aw/actions/validate_secrets.cjs');
            await main();

      - name: Upload secret validation report
        if: always()
        uses: ` + GetActionPin("actions/upload-artifact") + `
        with:
          name: secret-validation-report
          path: secret-validation-report.md
          retention-days: 30
          if-no-files-found: warn
`)
	}

	content := yaml.String()

	// Write the maintenance workflow file
	maintenanceFile := filepath.Join(workflowDir, "agentics-maintenance.yml")
	maintenanceLog.Printf("Writing maintenance workflow to %s", maintenanceFile)

	if err := os.WriteFile(maintenanceFile, []byte(content), 0644); err != nil {
		return fmt.Errorf("failed to write maintenance workflow: %w", err)
	}

	maintenanceLog.Print("Maintenance workflow generated successfully")
	return nil
}

package workflow

import (
	"fmt"
	"strings"

	"github.com/github/gh-aw/pkg/logger"
)

var actionRefLog = logger.New("workflow:action_reference")

const (
	// GitHubOrgRepo is the organization and repository name for custom action references
	GitHubOrgRepo = "github/gh-aw"

	// GitHubActionsOrgRepo is the organization and repository name for the external gh-aw-actions repository
	GitHubActionsOrgRepo = "github/gh-aw-actions"
)

// ResolveSetupActionReference resolves the actions/setup action reference based on action mode and version.
// This is a standalone helper function that can be used by both Compiler methods and standalone
// workflow generators (like maintenance workflow) that don't have access to WorkflowData.
//
// Parameters:
//   - actionMode: The action mode (dev, release, or action)
//   - version: The version string to use for release/action mode
//   - actionTag: Optional override tag/SHA (takes precedence over version when in release mode)
//   - resolver: Optional ActionSHAResolver for dynamic SHA resolution (can be nil for standalone use)
//
// Returns:
//   - For dev mode: "./actions/setup" (local path)
//   - For release mode with resolver: "github/gh-aw/actions/setup@<sha> # <version>" (SHA-pinned)
//   - For release mode without resolver: "github/gh-aw/actions/setup@<version>" (tag-based, SHA resolved later)
//   - For action mode with resolver: "github/gh-aw-actions/setup@<sha> # <version>" (SHA-pinned)
//   - For action mode without resolver: "github/gh-aw-actions/setup@<version>" (tag-based, SHA resolved later)
//   - Falls back to local path if version is invalid in release/action mode
func ResolveSetupActionReference(actionMode ActionMode, version string, actionTag string, resolver ActionSHAResolver) string {
	return resolveSetupActionRef(actionMode, version, actionTag, resolver, "")
}

// resolveSetupActionRef is the internal implementation of ResolveSetupActionReference
// that accepts an optional actionsOrgRepo override. When actionsOrgRepo is empty,
// GitHubActionsOrgRepo is used.
func resolveSetupActionRef(actionMode ActionMode, version string, actionTag string, resolver ActionSHAResolver, actionsOrgRepo string) string {
	if actionsOrgRepo == "" {
		actionsOrgRepo = GitHubActionsOrgRepo
	}

	localPath := "./actions/setup"

	// Dev mode - return local path
	if actionMode == ActionModeDev {
		actionRefLog.Printf("Dev mode: using local action path: %s", localPath)
		return localPath
	}

	// Action mode - use external gh-aw-actions repository with SHA pinning if possible
	if actionMode == ActionModeAction {
		// Use actionTag if provided, otherwise fall back to version
		tag := actionTag
		if tag == "" {
			tag = version
		}

		// Check if tag is valid for action mode
		if tag == "" || tag == "dev" {
			actionRefLog.Print("WARNING: No release tag available in binary version (version is 'dev' or empty), falling back to local path")
			return localPath
		}

		// Construct the remote reference: <actionsOrgRepo>/setup@tag
		actionRepo := actionsOrgRepo + "/setup"
		remoteRef := fmt.Sprintf("%s@%s", actionRepo, tag)

		// If a resolver is available, try to resolve the SHA
		if resolver != nil {
			sha, err := resolver.ResolveSHA(actionRepo, tag)
			if err == nil && sha != "" {
				pinnedRef := formatActionReference(actionRepo, sha, tag)
				actionRefLog.Printf("Action mode: resolved %s to SHA-pinned reference: %s", remoteRef, pinnedRef)
				return pinnedRef
			}
			if err != nil {
				actionRefLog.Printf("Failed to resolve SHA for %s@%s: %v", actionRepo, tag, err)
			}
		}

		// If no resolver or SHA resolution failed, return tag-based reference
		actionRefLog.Printf("Action mode: using tag-based external actions repo reference: %s (SHA will be resolved later)", remoteRef)
		return remoteRef
	}

	// Release mode - convert to remote reference
	if actionMode == ActionModeRelease {
		actionPath := strings.TrimPrefix(localPath, "./")

		// Use actionTag if provided, otherwise fall back to version
		tag := actionTag
		if tag == "" {
			tag = version
		}

		// Check if tag is valid for release mode
		if tag == "" || tag == "dev" {
			actionRefLog.Print("WARNING: No release tag available in binary version (version is 'dev' or empty), falling back to local path")
			return localPath
		}

		// Construct the remote reference with tag: github/gh-aw/actions/setup@tag
		actionRepo := fmt.Sprintf("%s/%s", GitHubOrgRepo, actionPath)
		remoteRef := fmt.Sprintf("%s@%s", actionRepo, tag)

		// If a resolver is available, try to resolve the SHA
		if resolver != nil {
			sha, err := resolver.ResolveSHA(actionRepo, tag)
			if err == nil && sha != "" {
				pinnedRef := formatActionReference(actionRepo, sha, tag)
				actionRefLog.Printf("Release mode: resolved %s to SHA-pinned reference: %s", remoteRef, pinnedRef)
				return pinnedRef
			}
			if err != nil {
				actionRefLog.Printf("Failed to resolve SHA for %s@%s: %v", actionRepo, tag, err)
			}
		}

		// If no resolver or SHA resolution failed, return tag-based reference
		// This is for backward compatibility with standalone workflow generators
		actionRefLog.Printf("Release mode: using tag-based remote action reference: %s (SHA will be resolved later)", remoteRef)
		return remoteRef
	}

	// Unknown mode - default to local path
	actionRefLog.Printf("WARNING: Unknown action mode %s, defaulting to local path", actionMode)
	return localPath
}

// resolveActionReference converts a local action path to the appropriate reference
// based on the current action mode (dev vs release vs action).
// If action-tag is specified in features, it overrides the mode check and enables action mode behavior
// (using the github/gh-aw-actions external repository).
// For dev mode: returns the local path as-is (e.g., "./actions/create-issue")
// For release mode: converts to SHA-pinned remote reference (e.g., "github/gh-aw/actions/create-issue@SHA # tag")
// For action mode: converts to SHA-pinned reference in external repo if possible (e.g., "github/gh-aw-actions/create-issue@SHA # version")
func (c *Compiler) resolveActionReference(localActionPath string, data *WorkflowData) string {
	// Check if action-tag is specified in features - if so, override mode and use action mode behavior
	hasActionTag := false
	var frontmatterActionTag string
	if data != nil && data.Features != nil {
		if actionTagVal, exists := data.Features["action-tag"]; exists {
			if actionTagStr, ok := actionTagVal.(string); ok && actionTagStr != "" {
				hasActionTag = true
				frontmatterActionTag = actionTagStr
				actionRefLog.Printf("action-tag feature detected: %s - using action mode behavior", actionTagStr)
			}
		}
	}

	// For ./actions/setup, check for compiler-level actionTag override first
	if localActionPath == "./actions/setup" {
		// Use compiler actionTag if available, otherwise check features
		var resolver ActionSHAResolver
		if data != nil && data.ActionResolver != nil {
			resolver = data.ActionResolver
		}
		if c.actionTag != "" {
			return resolveSetupActionRef(c.actionMode, c.version, c.actionTag, resolver, c.effectiveActionsRepo())
		}
		if !hasActionTag {
			return resolveSetupActionRef(c.actionMode, c.version, "", resolver, c.effectiveActionsRepo())
		}
		// hasActionTag is true and no compiler actionTag: use action mode with the frontmatter tag
		return resolveSetupActionRef(ActionModeAction, c.version, frontmatterActionTag, resolver, c.effectiveActionsRepo())
	}

	// Action mode - use external gh-aw-actions repository
	if c.actionMode == ActionModeAction || hasActionTag {
		return c.convertToExternalActionsRef(localActionPath, data)
	}

	// Use release mode
	if c.actionMode == ActionModeRelease {
		// Convert to tag-based remote reference for release
		remoteRef := c.convertToRemoteActionRef(localActionPath, data)
		if remoteRef == "" {
			actionRefLog.Printf("WARNING: Could not resolve remote reference for %s", localActionPath)
			return ""
		}

		// Now resolve the tag to a SHA using action pins
		// Extract repo and version from the remote reference (format: "repo/path@version")
		actionRepo := extractActionRepo(remoteRef)
		version := extractActionVersion(remoteRef)

		if actionRepo != "" && version != "" {
			// Resolve the SHA using action pins
			pinnedRef, err := GetActionPinWithData(actionRepo, version, data)
			if err != nil {
				// In strict mode, GetActionPinWithData returns an error
				actionRefLog.Printf("Failed to pin action %s@%s: %v", actionRepo, version, err)
				return ""
			}
			if pinnedRef != "" {
				// Successfully resolved to SHA
				actionRefLog.Printf("Release mode: resolved %s to SHA-pinned reference: %s", remoteRef, pinnedRef)
				return pinnedRef
			}
		}

		// If we couldn't resolve to SHA, return the tag-based reference
		// This happens in non-strict mode when no pin is available
		actionRefLog.Printf("Release mode: using tag-based remote action reference: %s", remoteRef)
		return remoteRef
	}

	// Dev mode - return local path
	if c.actionMode == ActionModeDev {
		actionRefLog.Printf("Dev mode: using local action path: %s", localActionPath)
		return localActionPath
	}

	// Default to dev mode for unknown modes
	actionRefLog.Printf("WARNING: Unknown action mode %s, defaulting to dev mode", c.actionMode)
	return localActionPath
}

// convertToRemoteActionRef converts a local action path to a tag-based remote reference
// that will be resolved to a SHA later in the release pipeline using action pins.
// Uses the action-tag from WorkflowData.Features if specified (for testing), otherwise uses the version stored in the compiler binary.
// If compiler has actionTag set, it takes priority over both.
// Example: "./actions/create-issue" -> "github/gh-aw/actions/create-issue@v1.0.0"
func (c *Compiler) convertToRemoteActionRef(localPath string, data *WorkflowData) string {
	// Strip the leading "./" if present
	actionPath := strings.TrimPrefix(localPath, "./")

	// Priority order for tag selection:
	// 1. Compiler actionTag (from --action-tag flag)
	// 2. WorkflowData.Features["action-tag"] (from frontmatter)
	// 3. Compiler version
	var tag string

	// Check compiler actionTag first (highest priority)
	if c.actionTag != "" {
		tag = c.actionTag
		actionRefLog.Printf("Using action-tag from compiler: %s", tag)
	} else if data != nil && data.Features != nil {
		// Check WorkflowData.Features for action-tag
		if actionTagVal, exists := data.Features["action-tag"]; exists {
			if actionTagStr, ok := actionTagVal.(string); ok && actionTagStr != "" {
				tag = actionTagStr
				actionRefLog.Printf("Using action-tag from features: %s", tag)
			}
		}
	}

	// Fall back to compiler version if no tag specified
	if tag == "" {
		tag = c.version
		if tag == "" || tag == "dev" {
			actionRefLog.Print("WARNING: No release tag available in binary version (version is 'dev' or empty)")
			return ""
		}
		actionRefLog.Printf("Using tag from binary version: %s", tag)
	}

	// Construct the remote reference with tag: github/gh-aw/actions/name@tag
	// The SHA will be resolved later by action pinning infrastructure
	remoteRef := fmt.Sprintf("%s/%s@%s", GitHubOrgRepo, actionPath, tag)
	actionRefLog.Printf("Remote reference: %s (SHA will be resolved via action pins)", remoteRef)

	return remoteRef
}

// convertToExternalActionsRef converts a local action path to a SHA-pinned (if possible) reference
// in the external github/gh-aw-actions repository.
// Example: "./actions/create-issue" -> "github/gh-aw-actions/create-issue@<sha> # v1.0.0"
//
// If SHA resolution fails (no resolver or pin not available), falls back to version-tagged reference:
// Example: "./actions/create-issue" -> "github/gh-aw-actions/create-issue@v1.0.0"
func (c *Compiler) convertToExternalActionsRef(localPath string, data *WorkflowData) string {
	// Strip the leading "./" prefix
	actionPath := strings.TrimPrefix(localPath, "./")

	// Strip the "actions/" prefix to get just the action name
	// e.g., "actions/create-issue" -> "create-issue"
	actionName := strings.TrimPrefix(actionPath, "actions/")

	// Determine tag: use compiler actionTag or version
	tag := c.actionTag
	if tag == "" {
		if data != nil && data.Features != nil {
			if actionTagVal, exists := data.Features["action-tag"]; exists {
				if actionTagStr, ok := actionTagVal.(string); ok && actionTagStr != "" {
					tag = actionTagStr
				}
			}
		}
	}
	if tag == "" {
		tag = c.version
		if tag == "" || tag == "dev" {
			actionRefLog.Print("WARNING: No release tag available in binary version (version is 'dev' or empty)")
			return ""
		}
	}

	// Construct the external actions reference: <actionsRepo>/action-name@tag
	actionRepo := fmt.Sprintf("%s/%s", c.effectiveActionsRepo(), actionName)
	remoteRef := fmt.Sprintf("%s@%s", actionRepo, tag)

	// Try to resolve the SHA using action pins
	if data != nil {
		pinnedRef, err := GetActionPinWithData(actionRepo, tag, data)
		if err != nil {
			// Log and fall through to tag-based reference (action mode is not strict)
			actionRefLog.Printf("Failed to pin action %s@%s: %v, falling back to tag-based reference", actionRepo, tag, err)
		} else if pinnedRef != "" {
			actionRefLog.Printf("Action mode: resolved %s to SHA-pinned reference: %s", remoteRef, pinnedRef)
			return pinnedRef
		}
	}

	// If SHA resolution unavailable or pin not found, return tag-based reference
	actionRefLog.Printf("Action mode: using tag-based external actions repo reference: %s (SHA will be resolved later)", remoteRef)
	return remoteRef
}

package workflow

import (
	_ "embed"
	"encoding/json"
	"fmt"
	"os"
	"sort"
	"strings"
	"sync"

	"github.com/github/gh-aw/pkg/console"
	"github.com/github/gh-aw/pkg/logger"
	"github.com/github/gh-aw/pkg/sliceutil"
)

var actionPinsLog = logger.New("workflow:action_pins")

//go:embed data/action_pins.json
var actionPinsJSON []byte

// formatActionReference formats an action reference with repo, SHA, and version.
// Example: "actions/checkout@abc123 # v4.1.0"
func formatActionReference(repo, sha, version string) string {
	return fmt.Sprintf("%s@%s # %s", repo, sha, version)
}

// formatActionCacheKey generates a cache key for action resolution.
// Example: "actions/checkout@v4"
func formatActionCacheKey(repo, version string) string {
	return fmt.Sprintf("%s@%s", repo, version)
}

// ActionPin represents a pinned GitHub Action with its commit SHA
type ActionPin struct {
	Repo    string                      `json:"repo"`             // e.g., "actions/checkout"
	Version string                      `json:"version"`          // e.g., "v5" - the golden/default version
	SHA     string                      `json:"sha"`              // Full commit SHA for the pinned version
	Inputs  map[string]*ActionYAMLInput `json:"inputs,omitempty"` // optional cached inputs (not used for SHA pinning)
}

// ActionPinsData represents the structure of the embedded JSON file
// This matches the schema used by ActionCache for consistency
type ActionPinsData struct {
	Entries map[string]ActionPin `json:"entries"` // key: "repo@version"
}

var (
	// cachedActionPins holds the parsed and sorted action pins
	cachedActionPins []ActionPin
	// actionPinsOnce ensures the action pins are loaded only once
	actionPinsOnce sync.Once
)

// getActionPins returns the action pins from the embedded JSON
// Returns a sorted slice of action pins (by version descending, then by repo name)
// The data is parsed once on first call and cached for subsequent calls
func getActionPins() []ActionPin {
	actionPinsOnce.Do(func() {
		actionPinsLog.Print("Unmarshaling action pins from embedded JSON (first call, will be cached)")

		var data ActionPinsData
		if err := json.Unmarshal(actionPinsJSON, &data); err != nil {
			actionPinsLog.Printf("Failed to unmarshal action pins JSON: %v", err)
			panic(fmt.Sprintf("failed to load action pins: %v", err))
		}

		// Detect and log key/version mismatches
		mismatchCount := 0
		for key, pin := range data.Entries {
			// Extract version from key (format: "repo@version")
			if idx := strings.LastIndex(key, "@"); idx != -1 {
				keyVersion := key[idx+1:]
				if keyVersion != pin.Version {
					mismatchCount++
					// Safely truncate SHA for logging
					shortSHA := pin.SHA
					if len(pin.SHA) > 8 {
						shortSHA = pin.SHA[:8]
					}
					actionPinsLog.Printf("WARNING: Key/version mismatch in action_pins.json: key=%s has version=%s but pin.Version=%s (sha=%s)",
						key, keyVersion, pin.Version, shortSHA)
				}
			}
		}
		if mismatchCount > 0 {
			actionPinsLog.Printf("Found %d key/version mismatches in action_pins.json", mismatchCount)
		}

		// Convert map values to slice - immutable initialization
		pins := make([]ActionPin, 0, len(data.Entries))
		for _, pin := range data.Entries {
			pins = append(pins, pin)
		}

		// Sort by version (descending) then by repo name (ascending)
		// Use standard library sort for better performance O(n log n) vs O(n²)
		sort.Slice(pins, func(i, j int) bool {
			// Compare versions first (descending order - higher version first)
			if pins[i].Version != pins[j].Version {
				return pins[i].Version > pins[j].Version
			}
			// Same version, sort by repo name (ascending order)
			return pins[i].Repo < pins[j].Repo
		})

		actionPinsLog.Printf("Successfully unmarshaled and sorted %d action pins from JSON", len(pins))
		cachedActionPins = pins
	})

	return cachedActionPins
}

// sortPinsByVersion sorts action pins by version in descending order (highest first).
// This function returns a new sorted slice without modifying the input.
// This is an immutable operation for better safety and clarity.
func sortPinsByVersion(pins []ActionPin) []ActionPin {
	// Create a copy to avoid mutating the input
	result := make([]ActionPin, len(pins))
	copy(result, pins)

	sort.Slice(result, func(i, j int) bool {
		// Strip 'v' prefix for comparison
		v1 := strings.TrimPrefix(result[i].Version, "v")
		v2 := strings.TrimPrefix(result[j].Version, "v")
		// Return true if v1 > v2 to get descending order
		return compareVersions(v1, v2) > 0
	})

	return result
}

// GetActionPin returns the pinned action reference for a given action repository
// When multiple versions exist for the same repo, it returns the latest version by semver
// If no pin is found, it returns an empty string
// The returned reference includes a comment with the version tag (e.g., "repo@sha # v1")
func GetActionPin(actionRepo string) string {
	actionPins := getActionPins()

	// Find all pins matching the repo - using functional filter
	matchingPins := sliceutil.Filter(actionPins, func(pin ActionPin) bool {
		return pin.Repo == actionRepo
	})

	if len(matchingPins) == 0 {
		// If no pin exists, return empty string to signal that this action is not pinned
		return ""
	}

	// Sort matching pins by version (descending - latest first) - immutable operation
	sortedPins := sortPinsByVersion(matchingPins)

	// Return the latest version (first after sorting)
	latestPin := sortedPins[0]
	return formatActionReference(actionRepo, latestPin.SHA, latestPin.Version)
}

// GetActionPinWithData returns the pinned action reference for a given action@version
// It tries dynamic resolution first, then falls back to hardcoded pins
// If resolution fails, emits a warning and returns empty string (in both strict and non-strict modes)
// The returned reference includes a comment with the version tag (e.g., "repo@sha # v1")
func GetActionPinWithData(actionRepo, version string, data *WorkflowData) (string, error) {
	actionPinsLog.Printf("Resolving action pin: repo=%s, version=%s, strict_mode=%t", actionRepo, version, data.StrictMode)

	// Check if version is already a full 40-character SHA
	isAlreadySHA := isValidFullSHA(version)

	// First try dynamic resolution if resolver is available (but not for SHAs, as they can't be resolved)
	if data.ActionResolver != nil && !isAlreadySHA {
		actionPinsLog.Printf("Attempting dynamic resolution for %s@%s", actionRepo, version)
		sha, err := data.ActionResolver.ResolveSHA(actionRepo, version)
		if err == nil && sha != "" {
			actionPinsLog.Printf("Dynamic resolution succeeded: %s@%s → %s", actionRepo, version, sha)

			// Successfully resolved - cache will be saved at end of compilation
			actionPinsLog.Printf("Successfully resolved action pin (cache marked dirty, will save at end)")
			result := formatActionReference(actionRepo, sha, version)
			actionPinsLog.Printf("Returning pinned reference: %s", result)
			return result, nil
		}
		actionPinsLog.Printf("Dynamic resolution failed for %s@%s: %v", actionRepo, version, err)
	} else {
		if isAlreadySHA {
			actionPinsLog.Printf("Version is already a SHA, skipping dynamic resolution")
		} else {
			actionPinsLog.Printf("No action resolver available, skipping dynamic resolution")
		}
	}

	// Dynamic resolution failed, try hardcoded pins
	actionPinsLog.Printf("Falling back to hardcoded pins for %s@%s", actionRepo, version)
	actionPins := getActionPins()

	// Find all pins matching the repo - using functional filter
	matchingPins := sliceutil.Filter(actionPins, func(pin ActionPin) bool {
		return pin.Repo == actionRepo
	})

	if len(matchingPins) == 0 {
		// No pins found for this repo, will handle below
		actionPinsLog.Printf("No hardcoded pins found for %s", actionRepo)
	} else {
		actionPinsLog.Printf("Found %d hardcoded pin(s) for %s", len(matchingPins), actionRepo)

		// Sort matching pins by version (descending - highest first) - immutable operation
		matchingPins = sortPinsByVersion(matchingPins)

		// First, try to find an exact version match (for version tags)
		for _, pin := range matchingPins {
			if pin.Version == version {
				actionPinsLog.Printf("Exact version match: requested=%s, found=%s", version, pin.Version)
				return formatActionReference(actionRepo, pin.SHA, pin.Version), nil
			}
		}

		// If version is a SHA, check if it matches any hardcoded pin's SHA
		if isAlreadySHA {
			for _, pin := range matchingPins {
				if pin.SHA == version {
					actionPinsLog.Printf("Exact SHA match: requested=%s, found version=%s", version, pin.Version)
					return formatActionReference(actionRepo, pin.SHA, pin.Version), nil
				}
			}
			// SHA provided but doesn't match any hardcoded pin - return it as-is without warnings
			actionPinsLog.Printf("SHA %s not found in hardcoded pins, returning as-is", version)
			return formatActionReference(actionRepo, version, version), nil
		}

		// No exact match found
		// In non-strict mode, find the highest semver-compatible version
		// Semver compatibility means respecting major version boundaries
		// (e.g., v5 -> highest v5.x.x, not v6.x.x)
		if !data.StrictMode && len(matchingPins) > 0 {
			// Filter for semver-compatible pins (matching major version) - using functional filter
			compatiblePins := sliceutil.Filter(matchingPins, func(pin ActionPin) bool {
				return isSemverCompatible(pin.Version, version)
			})

			// If we found compatible pins, use the highest one (first after sorting)
			// Otherwise fall back to the highest overall pin
			var selectedPin ActionPin
			if len(compatiblePins) > 0 {
				selectedPin = compatiblePins[0]
				actionPinsLog.Printf("No exact match for version %s, using highest semver-compatible version: %s", version, selectedPin.Version)
			} else {
				selectedPin = matchingPins[0]
				actionPinsLog.Printf("No exact match for version %s, no semver-compatible versions found, using highest available: %s", version, selectedPin.Version)
			}

			// Only emit warning if the version is not a SHA (SHAs shouldn't generate warnings)
			if !isAlreadySHA {
				// Initialize the warning cache if needed
				if data.ActionPinWarnings == nil {
					data.ActionPinWarnings = make(map[string]bool)
				}

				// Create a cache key for this action@version combination
				cacheKey := formatActionCacheKey(actionRepo, version)

				// Only emit warning if we haven't already warned about this action
				if !data.ActionPinWarnings[cacheKey] {
					warningMsg := fmt.Sprintf("Unable to resolve %s@%s dynamically, using hardcoded pin for %s@%s",
						actionRepo, version, actionRepo, selectedPin.Version)
					fmt.Fprintln(os.Stderr, console.FormatWarningMessage(warningMsg))
					data.ActionPinWarnings[cacheKey] = true
				}
			}
			actionPinsLog.Printf("Using version in non-strict mode: %s@%s (requested) → %s@%s (used)",
				actionRepo, version, actionRepo, selectedPin.Version)
			// Use the requested version in the comment, not the pin's version
			// This preserves the user's intent (e.g., v8 instead of v8.0.0)
			return formatActionReference(actionRepo, selectedPin.SHA, version), nil
		}
	}

	// No pin available - emit warning in both strict and non-strict modes
	// Note: This used to fail in strict mode, but it's not always possible to resolve pins
	// so we now emit a warning and continue compilation in both modes

	// In both strict and non-strict mode, emit warning and return empty string (unless it's already a SHA)
	if isAlreadySHA {
		// If version is already a SHA and we couldn't find it in pins, return it as-is without warnings
		actionPinsLog.Printf("SHA %s not found in hardcoded pins, returning as-is", version)
		return formatActionReference(actionRepo, version, version), nil
	}

	// Initialize the warning cache if needed
	if data.ActionPinWarnings == nil {
		data.ActionPinWarnings = make(map[string]bool)
	}

	// Create a cache key for this action@version combination
	cacheKey := formatActionCacheKey(actionRepo, version)

	// Only emit warning if we haven't already warned about this action
	if !data.ActionPinWarnings[cacheKey] {
		warningMsg := fmt.Sprintf("Unable to pin action %s@%s", actionRepo, version)
		if data.ActionResolver != nil {
			warningMsg = fmt.Sprintf("Unable to pin action %s@%s: resolution failed", actionRepo, version)
		}
		fmt.Fprintln(os.Stderr, console.FormatWarningMessage(warningMsg))
		data.ActionPinWarnings[cacheKey] = true
	}
	return "", nil
}

// ApplyActionPinToTypedStep applies SHA pinning to a WorkflowStep if it uses an action.
// Returns a modified copy of the step with pinned references.
// If the step doesn't use an action or the action is not pinned, returns the original step.
func ApplyActionPinToTypedStep(step *WorkflowStep, data *WorkflowData) *WorkflowStep {
	// Check if step uses an action
	if step == nil || !step.IsUsesStep() {
		return step
	}

	actionPinsLog.Printf("Applying action pin to step: uses=%s", step.Uses)

	// Extract action repo and version from uses field
	actionRepo := extractActionRepo(step.Uses)
	if actionRepo == "" {
		return step
	}

	version := extractActionVersion(step.Uses)
	if version == "" {
		// No version specified, can't pin
		return step
	}

	// Try to get pinned SHA
	pinnedRef, err := GetActionPinWithData(actionRepo, version, data)
	if err != nil {
		// In strict mode, this would have already been handled by GetActionPinWithData
		// In normal mode, we just return the original step
		return step
	}

	if pinnedRef == "" {
		// No pin available for this action, return original step
		return step
	}

	actionPinsLog.Printf("Pinning action: %s@%s -> %s", actionRepo, version, pinnedRef)

	// Create a copy of the step with the pinned reference
	result := step.Clone()
	result.Uses = pinnedRef

	return result
}

// extractActionRepo extracts the action repository from a uses string
// For example:
//   - "actions/checkout@v5" -> "actions/checkout"
//   - "actions/setup-node@v6" -> "actions/setup-node"
//   - "github/codeql-action/upload-sarif@v3" -> "github/codeql-action/upload-sarif"
//   - "actions/checkout" -> "actions/checkout"
func extractActionRepo(uses string) string {
	// Split on @ to separate repo from version/ref
	before, _, ok := strings.Cut(uses, "@")
	if !ok {
		// No @ found, return the whole string
		return uses
	}
	// Return everything before the @
	return before
}

// extractActionVersion extracts the version from a uses string
// For example:
//   - "actions/checkout@v5" -> "v4"
//   - "actions/setup-node@v6" -> "v5"
//   - "actions/checkout" -> ""
func extractActionVersion(uses string) string {
	// Split on @ to separate repo from version/ref
	_, after, ok := strings.Cut(uses, "@")
	if !ok {
		// No @ found, no version
		return ""
	}
	// Return everything after the @
	return after
}

// ApplyActionPinsToTypedSteps applies SHA pinning to a slice of typed WorkflowStep pointers
// Returns a new slice with pinned references - this is the type-safe version
func ApplyActionPinsToTypedSteps(steps []*WorkflowStep, data *WorkflowData) []*WorkflowStep {
	actionPinsLog.Printf("Applying action pins to %d typed steps", len(steps))
	if steps == nil {
		return nil
	}

	result := make([]*WorkflowStep, 0, len(steps))
	for i, step := range steps {
		if step == nil {
			actionPinsLog.Printf("Skipping nil step at index %d", i)
			result = append(result, nil)
			continue
		}

		pinnedStep := ApplyActionPinToTypedStep(step, data)
		result = append(result, pinnedStep)
	}

	actionPinsLog.Printf("Successfully applied pins to %d typed steps", len(result))
	return result
}

// GetActionPinByRepo returns the ActionPin for a given repository, if it exists
// When multiple versions exist for the same repo, it returns the latest version by semver
func GetActionPinByRepo(repo string) (ActionPin, bool) {
	actionPins := getActionPins()

	// Find all pins matching the repo - using functional filter
	matchingPins := sliceutil.Filter(actionPins, func(pin ActionPin) bool {
		return pin.Repo == repo
	})

	if len(matchingPins) == 0 {
		return ActionPin{}, false
	}

	// Sort matching pins by version (descending - latest first) - immutable operation
	sortedPins := sortPinsByVersion(matchingPins)

	// Return the latest version (first after sorting)
	return sortedPins[0], true
}

