    permissions:
      contents: read

    steps:
      - name: Checkout repository
        uses: actions/checkout@v6
      - name: Install gh-aw extension
        uses: %s%s
        with:
          version: %s
`, actionRepo, actionRef, version)
	}

	// Default (dev/script mode): use curl to download install script
	return `name: "Copilot Setup Steps"

