// generateInstallCLISteps generates YAML steps to install or build the gh-aw CLI.
// In dev mode: builds from source using Setup Go + Build gh-aw (./gh-aw binary available)
// In release mode: installs the released CLI via the setup-cli action (gh aw available)
// In action mode: installs the released CLI via the gh-aw-actions/setup-cli action (gh aw available)
func generateInstallCLISteps(actionMode ActionMode, version string, actionTag string) string {
	return generateInstallCLIStepsWithResolver(actionMode, version, actionTag, nil)
}

// generateInstallCLIStepsWithResolver generates YAML steps to install or build the gh-aw CLI,
// with optional SHA resolution for setup-cli via a resolver. When a resolver is available,
// the setup-cli action reference will be pinned to a commit SHA instead of a mutable tag.
func generateInstallCLIStepsWithResolver(actionMode ActionMode, version string, actionTag string, resolver ActionSHAResolver) string {
	if actionMode == ActionModeDev {
		return `      - name: Setup Go
        uses: ` + GetActionPin("actions/setup-go") + `
        with:
          go-version-file: go.mod
          cache: true

      - name: Build gh-aw
        run: make build

`
	}

	cliTag := actionTag
	if cliTag == "" {
		cliTag = version
	}

	// Action mode: use setup-cli action from external gh-aw-actions repository
	if actionMode == ActionModeAction {
		ref := resolveSetupCLIRef("github/gh-aw-actions/setup-cli", cliTag, resolver)
		return `      - name: Install gh-aw
        uses: ` + ref + `
        with:
          version: ` + cliTag + `

`
	}

	// Release mode: use setup-cli action (consistent with copilot-setup-steps.yml)
	ref := resolveSetupCLIRef("github/gh-aw/actions/setup-cli", cliTag, resolver)
	return `      - name: Install gh-aw
        uses: ` + ref + `
        with:
          version: ` + cliTag + `

`
}

// resolveSetupCLIRef resolves the setup-cli action reference to a SHA-pinned format when a resolver is available.
// When SHA resolution succeeds, returns "repo@<sha> # <version>".
// When SHA resolution fails or no resolver is available, falls back to "repo@<version>".
func resolveSetupCLIRef(repo, version string, resolver ActionSHAResolver) string {
	if resolver != nil {
		sha, err := resolver.ResolveSHA(repo, version)
		if err == nil && sha != "" {
			maintenanceLog.Printf("Resolved setup-cli reference: %s@%s -> SHA %s", repo, version, sha)
			return formatActionReference(repo, sha, version)
		}
		if err != nil {
			maintenanceLog.Printf("Failed to resolve SHA for %s@%s: %v, falling back to tag reference", repo, version, err)
		}
	}
	return fmt.Sprintf("%s@%s", repo, version)
}

